const r = await tools.exec_command({cmd:"python3 - <<'PY'
import gzip,json,collections,statistics
p='/app/sgl-profile-results/1784325586.8139856/1784325586.815403-TP-0.trace.json.gz'
with gzip.open(p,'rt') as f: ev=json.load(f)['traceEvents']

def union_stats(xs):
 xs=sorted((float(e['ts']),float(e['ts'])+float(e['dur'])) for e in xs)
 merged=[]
 for a,b in xs:
  if merged and a<=merged[-1][1]: merged[-1][1]=max(merged[-1][1],b)
  else: merged.append([a,b])
 span=merged[-1][1]-merged[0][0]; busy=sum(b-a for a,b in merged); idle=span-busy
 gaps=sorted(((merged[i+1][0]-merged[i][1],merged[i][1],merged[i+1][0]) for i in range(len(merged)-1)),reverse=True)
 return span,busy,idle,100*idle/span,merged,gaps
k=[e for e in ev if e.get('cat')=='kernel' and e.get('ph')=='X' and 'dur' in e]
for label,xs in [('all',k),('tid3',[e for e in k if e.get('tid')==3]),('tid2',[e for e in k if e.get('tid')==2])]:
 span,busy,idle,pct,m,g=union_stats(xs)
 print(label,'n',len(xs),'span_us',span,'busy_us',busy,'idle_us',idle,'idle_pct',pct,'merged',len(m))
 print('top gaps us',[(round(x[0],3),round((x[1]-m[0][0])/1000,3),round((x[2]-m[0][0])/1000,3)) for x in g[:20]])
# include kernel+memcpy+memset GPU engines
for cats in [('kernel','gpu_memcpy'),('kernel','gpu_memcpy','gpu_memset')]:
 xs=[e for e in ev if e.get('cat') in cats and e.get('ph')=='X' and 'dur' in e]
 print(cats,union_stats(xs)[:4])
PY","workdir":"/app","yield_time_ms":10000,"max_output_tokens":12000});
text(r.output);

