const r = await tools.exec_command({cmd:"python3 - <<'PY'
import gzip,json,collections
p='/app/sgl-profile-results/1784325586.8139856/1784325586.815403-TP-0.trace.json.gz'
with gzip.open(p,'rt') as f: ev=json.load(f)['traceEvents']
d2h=[e for e in ev if e.get('name')=='Memcpy DtoH (Device -> Host)']
print('count',len(d2h))
for i,e in enumerate(d2h): print(i,{k:e.get(k) for k in ('ts','dur','pid','tid','cat')},e.get('args'))
# external ID map to cpu ops
for e in d2h:
 xid=e.get('args',{}).get('External id')
 hits=[x for x in ev if x is not e and x.get('args',{}).get('External id')==xid]
 print('\nDTOH',e['ts'],e['dur'],'xid',xid)
 for x in hits: print(' ',x.get('cat'),x.get('name'),x.get('ts'),x.get('dur'),x.get('pid'),x.get('tid'),x.get('args'))
PY","workdir":"/app","yield_time_ms":10000,"max_output_tokens":30000});
text(r.output);

